BEGIN;  CREATE TABLE IF NOT EXISTS public.shipment_item_correction_audit (   id uuid PRIMARY KEY DEFAULT gen_random_uuid(),   shipment_id uuid NOT NULL REFERENCES public.shipment_logs(id),   reason text NOT NULL CHECK (char_length(btrim(reason)) BETWEEN 3 AND 500),   before_lines jsonb NOT NULL,   after_lines jsonb NOT NULL,   corrected_by uuid NOT NULL REFERENCES auth.users(id),   corrected_at timestamptz NOT NULL DEFAULT now() );  CREATE INDEX IF NOT EXISTS idx_shipment_item_correction_audit_shipment_time   ON public.shipment_item_correction_audit(shipment_id, corrected_at DESC);  ALTER TABLE public.shipment_item_correction_audit ENABLE ROW LEVEL SECURITY; DROP POLICY IF EXISTS "shipment_item_correction_audit_select" ON public.shipment_item_correction_audit; CREATE POLICY "shipment_item_correction_audit_select"   ON public.shipment_item_correction_audit   FOR SELECT TO authenticated   USING (public.is_manager());  REVOKE ALL ON TABLE public.shipment_item_correction_audit FROM PUBLIC, anon, authenticated; GRANT SELECT ON TABLE public.shipment_item_correction_audit TO authenticated;  CREATE OR REPLACE FUNCTION public.adjust_shipment_items_v1(   p_shipment_id uuid,   p_lines jsonb,   p_reason text ) RETURNS jsonb LANGUAGE plpgsql SECURITY DEFINER SET search_path = public, pg_temp AS $$ DECLARE   v_user_id uuid := auth.uid();   v_now timestamptz := now();   v_reason text := btrim(COALESCE(p_reason, ''));   v_shipment record;   v_plan record;   v_product_id uuid;   v_actual_qty numeric;   v_before jsonb := '[]'::jsonb;   v_after jsonb := '[]'::jsonb;   v_requested_count integer := 0;   v_valid_count integer := 0; BEGIN   IF v_user_id IS NULL OR NOT public.is_manager() THEN     RAISE EXCEPTION 'Ban khong co quyen dieu chinh hang tren chuyen.' USING ERRCODE = '42501';   END IF;    IF p_shipment_id IS NULL THEN     RAISE EXCEPTION 'Chua chon chuyen can dieu chinh.';   END IF;    IF p_lines IS NULL OR jsonb_typeof(p_lines) <> 'array' OR jsonb_array_length(p_lines) = 0 THEN     RAISE EXCEPTION 'Danh sach hang sau dieu chinh khong hop le.';   END IF;    IF jsonb_array_length(p_lines) > 100 THEN     RAISE EXCEPTION 'Moi chuyen chi duoc dieu chinh toi da 100 dong hang.';   END IF;    IF char_length(v_reason) < 3 OR char_length(v_reason) > 500 THEN     RAISE EXCEPTION 'Ly do dieu chinh phai tu 3 den 500 ky tu.';   END IF;    SELECT * INTO v_shipment   FROM public.shipment_logs   WHERE id = p_shipment_id AND deleted_at IS NULL   FOR UPDATE;    IF NOT FOUND THEN     RAISE EXCEPTION 'Khong tim thay chuyen hoac chuyen da bi huy.';   END IF;    IF NOT public.inventory_actor_can_change_transaction(v_shipment.shipment_date) THEN     RAISE EXCEPTION 'Ban khong co quyen sua chuyen o ngay nay.' USING ERRCODE = '42501';   END IF;    CREATE TEMP TABLE shipment_adjust_input (     plan_id uuid PRIMARY KEY,     target_qty numeric NOT NULL CHECK (target_qty >= 0)   ) ON COMMIT DROP;    INSERT INTO pg_temp.shipment_adjust_input(plan_id, target_qty)   SELECT x.plan_id, x.target_qty   FROM jsonb_to_recordset(p_lines) AS x(plan_id uuid, target_qty numeric);    GET DIAGNOSTICS v_requested_count = ROW_COUNT;    IF v_requested_count <> jsonb_array_length(p_lines) THEN     RAISE EXCEPTION 'Danh sach dieu chinh co ma ke hoach trung hoac thieu thong tin.';   END IF;    IF NOT EXISTS (SELECT 1 FROM pg_temp.shipment_adjust_input WHERE target_qty > 0) THEN     RAISE EXCEPTION 'Chuyen phai con it nhat mot dong hang co so luong lon hon 0.';   END IF;    PERFORM 1   FROM public.inventory_transactions t   WHERE t.shipment_id = p_shipment_id     AND t.tx_type = 'out'     AND t.adjusted_from_transaction_id IS NULL     AND t.deleted_at IS NULL   ORDER BY t.id   FOR UPDATE;    CREATE TEMP TABLE shipment_adjust_bases ON COMMIT DROP AS   SELECT t.id, t.delivery_plan_id, t.product_id, t.unit_cost   FROM public.inventory_transactions t   WHERE t.shipment_id = p_shipment_id     AND t.tx_type = 'out'     AND t.adjusted_from_transaction_id IS NULL     AND t.deleted_at IS NULL;    IF EXISTS (SELECT 1 FROM pg_temp.shipment_adjust_bases WHERE delivery_plan_id IS NULL) THEN     RAISE EXCEPTION 'Chuyen co dong hang cu khong gan ke hoach. Can kiem tra truoc khi dieu chinh.';   END IF;    PERFORM 1   FROM public.inventory_transactions a   WHERE a.adjusted_from_transaction_id IN (SELECT id FROM pg_temp.shipment_adjust_bases)     AND a.deleted_at IS NULL   ORDER BY a.id   FOR UPDATE;    CREATE TEMP TABLE shipment_adjust_old_lines ON COMMIT DROP AS   SELECT     b.delivery_plan_id AS plan_id,     b.product_id,     COALESCE(min(b.unit_cost), min(p.unit_price), 0) AS unit_cost,     COALESCE(sum(bq.effective_qty), 0) AS effective_qty   FROM pg_temp.shipment_adjust_bases b   JOIN public.products p ON p.id = b.product_id AND p.deleted_at IS NULL   JOIN LATERAL (     SELECT COALESCE(t.qty, 0)       + COALESCE(sum(CASE WHEN a.tx_type = 'adjust_in' THEN a.qty WHEN a.tx_type = 'adjust_out' THEN -a.qty ELSE 0 END), 0) AS effective_qty     FROM public.inventory_transactions t     LEFT JOIN public.inventory_transactions a       ON a.adjusted_from_transaction_id = t.id      AND a.deleted_at IS NULL      AND a.tx_type IN ('adjust_in', 'adjust_out')     WHERE t.id = b.id     GROUP BY t.id, t.qty   ) bq ON true   GROUP BY b.delivery_plan_id, b.product_id;    SELECT COALESCE(jsonb_agg(jsonb_build_object(     'plan_id', o.plan_id,     'product_id', o.product_id,     'qty', o.effective_qty   ) ORDER BY o.plan_id), '[]'::jsonb)   INTO v_before   FROM pg_temp.shipment_adjust_old_lines o;    CREATE TEMP TABLE shipment_adjust_affected_plans(plan_id uuid PRIMARY KEY) ON COMMIT DROP;   INSERT INTO pg_temp.shipment_adjust_affected_plans(plan_id)   SELECT plan_id FROM pg_temp.shipment_adjust_old_lines   UNION   SELECT plan_id FROM pg_temp.shipment_adjust_input;    PERFORM 1   FROM public.delivery_plans p   WHERE p.id IN (SELECT plan_id FROM pg_temp.shipment_adjust_affected_plans)   ORDER BY p.plan_date, p.id   FOR UPDATE;    SELECT count(*) INTO v_valid_count   FROM public.delivery_plans p   JOIN pg_temp.shipment_adjust_input i ON i.plan_id = p.id   WHERE p.deleted_at IS NULL     AND p.plan_date = v_shipment.shipment_date     AND p.customer_id IS NOT DISTINCT FROM v_shipment.customer_id     AND (       COALESCE(p.planned_qty, 0) + COALESCE(p.backlog_qty, 0) > 0       OR p.id IN (SELECT plan_id FROM pg_temp.shipment_adjust_old_lines)     );    IF v_valid_count <> v_requested_count THEN     RAISE EXCEPTION 'Ma hang them hoac doi phai co ke hoach dung ngay, dung khach va dung diem giao.';   END IF;    FOR v_product_id IN     SELECT DISTINCT p.product_id     FROM public.delivery_plans p     JOIN pg_temp.shipment_adjust_affected_plans a ON a.plan_id = p.id     ORDER BY p.product_id   LOOP     PERFORM public.inventory_lock_product(v_product_id);   END LOOP;    UPDATE public.inventory_transactions t   SET deleted_at = v_now,       deleted_by = v_user_id,       updated_at = v_now,       updated_by = v_user_id   WHERE t.id IN (SELECT id FROM pg_temp.shipment_adjust_bases)     AND t.deleted_at IS NULL;    UPDATE public.inventory_transactions a   SET deleted_at = v_now,       deleted_by = v_user_id,       updated_at = v_now,       updated_by = v_user_id   WHERE a.adjusted_from_transaction_id IN (SELECT id FROM pg_temp.shipment_adjust_bases)     AND a.deleted_at IS NULL;    INSERT INTO public.inventory_transactions (     tx_type,     tx_date,     product_id,     customer_id,     delivery_customer_id,     qty,     unit_cost,     note,     created_by,     updated_by,     product_name_snapshot,     product_spec_snapshot,     delivery_plan_id,     shipment_id   )   SELECT     'out',     v_shipment.shipment_date,     p.product_id,     p.customer_id,     p.delivery_customer_id,     i.target_qty,     COALESCE(o.unit_cost, pr.unit_price, 0),     'Xe ' || COALESCE(NULLIF(btrim(v_shipment.driver_1_name_snapshot), ''), 'Chua co tai xe') || ' - ' || v_shipment.shipment_no,     v_user_id,     v_user_id,     pr.name,     pr.spec,     p.id,     p_shipment_id   FROM pg_temp.shipment_adjust_input i   JOIN public.delivery_plans p ON p.id = i.plan_id   JOIN public.products pr ON pr.id = p.product_id AND pr.deleted_at IS NULL   LEFT JOIN pg_temp.shipment_adjust_old_lines o ON o.plan_id = p.id   WHERE i.target_qty > 0   ORDER BY p.id;    PERFORM set_config('app.skip_delivery_backlog_sync', 'on', true);    FOR v_plan IN     SELECT p.*     FROM public.delivery_plans p     JOIN pg_temp.shipment_adjust_affected_plans a ON a.plan_id = p.id     WHERE p.deleted_at IS NULL     ORDER BY p.plan_date, p.id   LOOP     SELECT COALESCE(sum(x.effective_qty), 0)     INTO v_actual_qty     FROM (       SELECT b.qty         + COALESCE(sum(CASE WHEN adj.tx_type = 'adjust_in' THEN adj.qty WHEN adj.tx_type = 'adjust_out' THEN -adj.qty ELSE 0 END), 0) AS effective_qty       FROM public.inventory_transactions b       LEFT JOIN public.inventory_transactions adj         ON adj.adjusted_from_transaction_id = b.id        AND adj.deleted_at IS NULL        AND adj.tx_type IN ('adjust_in', 'adjust_out')       WHERE b.delivery_plan_id = v_plan.id         AND b.tx_type = 'out'         AND b.adjusted_from_transaction_id IS NULL         AND b.deleted_at IS NULL       GROUP BY b.id, b.qty     ) x;      UPDATE public.delivery_plans     SET actual_qty = COALESCE(v_actual_qty, 0),         is_completed = CASE           WHEN is_completed THEN true           ELSE COALESCE(v_actual_qty, 0) >= COALESCE(planned_qty, 0) + COALESCE(backlog_qty, 0)         END,         updated_at = v_now,         updated_by = v_user_id     WHERE id = v_plan.id;   END LOOP;    PERFORM set_config('app.skip_delivery_backlog_sync', 'off', true);    FOR v_plan IN     SELECT p.id     FROM public.delivery_plans p     JOIN pg_temp.shipment_adjust_affected_plans a ON a.plan_id = p.id     WHERE p.deleted_at IS NULL     ORDER BY p.plan_date, p.id   LOOP     PERFORM public.sync_delivery_backlog(v_plan.id);   END LOOP;    SELECT COALESCE(jsonb_agg(jsonb_build_object(     'plan_id', i.plan_id,     'product_id', p.product_id,     'qty', i.target_qty   ) ORDER BY i.plan_id), '[]'::jsonb)   INTO v_after   FROM pg_temp.shipment_adjust_input i   JOIN public.delivery_plans p ON p.id = i.plan_id   WHERE i.target_qty > 0;    INSERT INTO public.shipment_item_correction_audit(     shipment_id,     reason,     before_lines,     after_lines,     corrected_by,     corrected_at   ) VALUES (     p_shipment_id,     v_reason,     v_before,     v_after,     v_user_id,     v_now   );    RETURN jsonb_build_object(     'success', true,     'shipment_id', p_shipment_id,     'before_lines', v_before,     'after_lines', v_after,     'message', 'Da dieu chinh hang tren chuyen. So chuyen va rate khong thay doi.'   ); EXCEPTION WHEN OTHERS THEN   PERFORM set_config('app.skip_delivery_backlog_sync', 'off', true);   RAISE; END; $$;  REVOKE ALL ON FUNCTION public.adjust_shipment_items_v1(uuid, jsonb, text) FROM PUBLIC, anon, authenticated; GRANT EXECUTE ON FUNCTION public.adjust_shipment_items_v1(uuid, jsonb, text) TO authenticated;  DO $$ DECLARE   v_signature regprocedure := to_regprocedure('public.shipment_outbound_delivery(jsonb,uuid,uuid,uuid,text,text,text,text,text,date,uuid)');   v_definition text;   v_updated text; BEGIN   IF v_signature IS NULL THEN     RAISE EXCEPTION 'Khong tim thay ham shipment_outbound_delivery dung chu ky.';   END IF;    SELECT pg_get_functiondef(v_signature) INTO v_definition;   v_updated := v_definition;    IF position('20260719_merge_disabled' IN v_updated) = 0 THEN     v_updated := replace(       v_updated,       E'  IF p_vehicle_id IS NULL AND p_existing_shipment_id IS NULL THEN',       E'  IF p_existing_shipment_id IS NOT NULL THEN\n    RAISE EXCEPTION ''Chuc nang ghep hang vao chuyen da tat. Hay dieu chinh tai Nhat ky giao hang.''; -- 20260719_merge_disabled\n  END IF;\n\n  IF p_vehicle_id IS NULL AND p_existing_shipment_id IS NULL THEN'     );      IF v_updated = v_definition THEN       RAISE EXCEPTION 'Khong tim thay vi tri khoa chuc nang ghep; dung migration de tranh sua nham ham live.';     END IF;   END IF;    IF position('20260719_trip_lock' IN v_updated) = 0 THEN     v_definition := v_updated;     v_updated := replace(       v_updated,       E'  ELSE\n    SELECT *\n    INTO v_vehicle',       E'  ELSE\n    PERFORM pg_advisory_xact_lock(hashtextextended(COALESCE(p_vehicle_id::text, '''') || '':'' || COALESCE(p_shipment_date::text, ''''), 20260719)); -- 20260719_trip_lock\n\n    SELECT *\n    INTO v_vehicle'     );      IF v_updated = v_definition THEN       RAISE EXCEPTION 'Khong tim thay vi tri them khoa dem chuyen; dung migration de tranh sua nham ham live.';     END IF;    END IF;    IF v_updated IS DISTINCT FROM v_definition      OR position('20260719_merge_disabled' IN v_definition) = 0 THEN     EXECUTE v_updated;   END IF; END; $$;  DO $$ DECLARE   v_signature regprocedure;   v_definition text;   v_updated text; BEGIN   FOREACH v_signature IN ARRAY ARRAY[     to_regprocedure('public.inventory_update_manual_transaction(uuid,date,uuid,numeric,numeric,text,uuid)'),     to_regprocedure('public.inventory_adjust_manual_transaction(uuid,numeric,date,numeric,text)'),     to_regprocedure('public.inventory_soft_delete_manual_transactions(uuid[])')   ]   LOOP     IF v_signature IS NULL THEN       RAISE EXCEPTION 'Thieu RPC kho thu cong can khoa giao dich chuyen.';     END IF;      SELECT pg_get_functiondef(v_signature) INTO v_definition;      IF position('Giao dich thuoc chuyen hang' IN v_definition) = 0 THEN       v_updated := replace(         v_definition,         E'    IF v_tx.tx_type NOT IN (''in'', ''out'') OR v_tx.adjusted_from_transaction_id IS NOT NULL THEN',         E'    IF v_tx.shipment_id IS NOT NULL THEN\n      RAISE EXCEPTION ''Giao dich thuoc chuyen hang. Vui long dieu chinh tai Nhat ky giao hang.'';\n    END IF;\n\n    IF v_tx.tx_type NOT IN (''in'', ''out'') OR v_tx.adjusted_from_transaction_id IS NOT NULL THEN'       );        IF v_updated = v_definition THEN         v_updated := replace(           v_definition,           E'  IF v_tx.tx_type NOT IN (''in'', ''out'') OR v_tx.adjusted_from_transaction_id IS NOT NULL THEN',           E'  IF v_tx.shipment_id IS NOT NULL THEN\n    RAISE EXCEPTION ''Giao dich thuoc chuyen hang. Vui long dieu chinh tai Nhat ky giao hang.'';\n  END IF;\n\n  IF v_tx.tx_type NOT IN (''in'', ''out'') OR v_tx.adjusted_from_transaction_id IS NOT NULL THEN'         );       END IF;        IF v_updated = v_definition THEN         RAISE EXCEPTION 'Khong tim thay vi tri khoa trong RPC %.', v_signature::text;       END IF;        EXECUTE v_updated;     END IF;   END LOOP; END; $$;  NOTIFY pgrst, 'reload schema'; COMMIT;
